import { readFileSync, writeFileSync } from 'fs';
try {
  const input = JSON.parse(readFileSync('/output/input.json', 'utf8'));
  const repo = input.repo;
  const labelFilter = input.labelFilter;
  const limit = Math.max(1, Math.min(100, Number(input.limit) || 20));
  const token = process.env.GITHUB_TOKEN;
  if (!repo) { console.error('repo trigger param is required'); process.exit(1); }
  if (!/^[\w.-]+\/[\w.-]+$/.test(repo)) { console.error(`invalid repo format: '${repo}' (expected owner/name)`); process.exit(1); }
  if (!token) { console.error('GITHUB_TOKEN secret not set on workflow'); process.exit(1); }
  const url = new URL(`https://api.github.com/repos/${repo}/issues`);
  url.searchParams.set('state', 'open');
  url.searchParams.set('per_page', String(limit));
  if (labelFilter) url.searchParams.set('labels', labelFilter);
  const res = await fetch(url, { headers: { Authorization: `Bearer ${token}`, Accept: 'application/vnd.github+json' } });
  if (!res.ok) { const body = await res.text(); console.error(`GitHub ${res.status} ${res.statusText}: ${body.slice(0,500)}`); process.exit(1); }
  const issues = await res.json();
  const onlyIssues = issues.filter((i) => !i.pull_request).slice(0, limit);
  const options = onlyIssues.map((i) => {
    const labels = (i.labels || []).map((l) => typeof l === 'string' ? l : l.name);
    return {
      id: String(i.number),
      label: `#${i.number} ${i.title}`,
      sublabel: labels.join(', '),
      href: i.html_url,
      badges: labels,
      currentAssignee: i.assignee?.login,
      raw: { issueNumber: i.number, title: i.title, labels, currentAssignee: i.assignee?.login, url: i.html_url },
    };
  });
  console.log(`Fetched ${options.length} open issue(s) from ${repo} (limit=${limit})`);
  writeFileSync('/output/result.json', JSON.stringify({ options, repo, summary: `Fetched ${options.length} open issue(s) from ${repo}` }));
} catch (err) {
  console.error('fetch-backlog crashed:', err?.stack || err?.message || String(err));
  process.exit(1);
}

import { readFileSync, writeFileSync } from 'fs';
try {
  const input = JSON.parse(readFileSync('/output/input.json', 'utf8'));
  const options = input.options || [];
  const repo = input.repo;
  const CATEGORIES = ['ux', 'tech-debt', 'infra', 'security', 'product', 'workflow', 'engine', 'bug', 'enhancement'];
  const categorySet = new Set(CATEGORIES.map((s) => s.toLowerCase()));
  const untagged = options.filter((o) => {
    const labels = (o.badges || o.raw?.labels || []).map((l) => String(l).toLowerCase());
    return !labels.some((l) => categorySet.has(l));
  });
  const needsTagging = untagged.length > 0;
  if (needsTagging) {
    writeFileSync('/output/result.json', JSON.stringify({ needsTagging: true, untaggedCount: untagged.length, options: untagged, repo, summary: `${untagged.length} of ${options.length} issue(s) need a category tag` }));
    console.log(`check-tags: ${untagged.length}/${options.length} untagged — routing to tag-issues`);
  } else {
    writeFileSync('/output/result.json', JSON.stringify({ needsTagging: false, options, repo, summary: `All ${options.length} issue(s) carry a category tag` }));
    console.log(`check-tags: all ${options.length} tagged — routing to propose-assignments`);
  }
} catch (err) {
  console.error('check-tags crashed:', err?.stack || err?.message || String(err));
  process.exit(1);
}

import { readFileSync, writeFileSync } from 'fs';
try {
  const input = JSON.parse(readFileSync('/output/input.json', 'utf8'));
  const assignments = input.assignments || [];
  const repo = input.repo || input.steps?.['fetch-backlog']?.repo;
  const token = process.env.GITHUB_TOKEN;
  const apiKey = process.env.PLATFORM_API_KEY;
  const baseUrl = process.env.APP_BASE_URL;
  if (repo && !/^[\w.-]+\/[\w.-]+$/.test(repo)) { console.error(`invalid repo format: '${repo}'`); process.exit(1); }
  const humanAssignments = [];
  const agentRuns = [];
  const errors = [];
  const ghHeaders = { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json', Accept: 'application/vnd.github+json' };
  for (const a of assignments) {
    const issueNumber = a.raw?.issueNumber ?? Number(a.itemId);
    try {
      if (a.assigneeKind === 'human') {
        if (!repo || !token) { errors.push({ itemId: a.itemId, kind: 'human', message: 'repo or GITHUB_TOKEN missing' }); continue; }
        const labelsRes = await fetch(`https://api.github.com/repos/${repo}/issues/${issueNumber}/labels`, {
          method: 'POST', headers: ghHeaders,
          body: JSON.stringify({ labels: [`priority/${a.priority}`] }),
        });
        if (!labelsRes.ok) { const body = await labelsRes.text(); errors.push({ itemId: a.itemId, kind: 'human', step: 'add-label', message: `GitHub POST /labels ${labelsRes.status}: ${body.slice(0,200)}` }); continue; }
        const assigneesRes = await fetch(`https://api.github.com/repos/${repo}/issues/${issueNumber}/assignees`, {
          method: 'POST', headers: ghHeaders,
          body: JSON.stringify({ assignees: [a.assigneeId] }),
        });
        if (!assigneesRes.ok) { const body = await assigneesRes.text(); errors.push({ itemId: a.itemId, kind: 'human', step: 'add-assignee', message: `GitHub POST /assignees ${assigneesRes.status}: ${body.slice(0,200)}` }); continue; }
        humanAssignments.push({ issueNumber, assignee: a.assigneeId, priority: a.priority });
      } else if (a.assigneeKind === 'agent') {
        if (!apiKey || !baseUrl) { errors.push({ itemId: a.itemId, kind: 'agent', message: 'PLATFORM_API_KEY or APP_BASE_URL missing' }); continue; }
        const res = await fetch(`${baseUrl}/api/processes`, {
          method: 'POST',
          headers: { 'X-Api-Key': apiKey, 'Content-Type': 'application/json' },
          body: JSON.stringify({ definitionName: a.assigneeId, triggerName: 'manual', triggeredBy: 'backlog-triage', payload: { issueNumber } }),
        });
        const body = res.headers.get('content-type')?.includes('json') ? await res.json() : { error: await res.text() };
        if (!res.ok) { errors.push({ itemId: a.itemId, kind: 'agent', message: `Mediforce POST ${res.status}: ${body.error || ''}` }); }
        else { agentRuns.push({ issueNumber, workflowId: a.assigneeId, runId: body.instanceId, url: `${baseUrl}/runs/${body.instanceId}` }); }
      }
    } catch (err) {
      errors.push({ itemId: a.itemId, kind: a.assigneeKind, message: String(err?.message ?? err) });
    }
  }
  console.log(`Dispatched ${humanAssignments.length} human(s), ${agentRuns.length} agent run(s), ${errors.length} error(s)`);
  writeFileSync('/output/result.json', JSON.stringify({ humanAssignments, agentRuns, errors, summary: `Dispatched ${humanAssignments.length} human(s), ${agentRuns.length} agent run(s), ${errors.length} error(s)` }));
} catch (err) {
  console.error('dispatch crashed:', err?.stack || err?.message || String(err));
  process.exit(1);
}

import { readFileSync, writeFileSync } from 'fs';
try {
  const input = JSON.parse(readFileSync('/output/input.json', 'utf8'));
  const rows = input.rows || [];
  const repo = input.repo || input.steps?.['fetch-backlog']?.repo;
  const token = process.env.GITHUB_TOKEN;
  if (repo && !/^[\w.-]+\/[\w.-]+$/.test(repo)) { console.error(`invalid repo format: '${repo}'`); process.exit(1); }
  const ghHeaders = { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json', Accept: 'application/vnd.github+json' };
  const applied = [];
  const errors = [];
  const ensured = new Set();
  for (const row of rows) {
    const itemId = row.itemId;
    const values = row.values || {};
    const labels = [];
    if (values.category) labels.push(String(values.category));
    if (values.priority) labels.push(`priority/${values.priority}`);
    try {
      if (!repo || !token) { errors.push({ itemId, message: 'repo or GITHUB_TOKEN missing' }); continue; }
      if (labels.length === 0) { errors.push({ itemId, message: 'no category/priority selected' }); continue; }
      let createFailed = false;
      for (const label of labels) {
        if (ensured.has(label)) continue;
        const createRes = await fetch(`https://api.github.com/repos/${repo}/labels`, {
          method: 'POST', headers: ghHeaders,
          body: JSON.stringify({ name: label, color: 'ededed' }),
        });
        if (createRes.ok || createRes.status === 422) { ensured.add(label); }
        else { const body = await createRes.text(); errors.push({ itemId, label, step: 'create-label', message: `GitHub POST /labels ${createRes.status}: ${body.slice(0,200)}` }); createFailed = true; break; }
      }
      if (createFailed) continue;
      const res = await fetch(`https://api.github.com/repos/${repo}/issues/${itemId}/labels`, {
        method: 'POST', headers: ghHeaders,
        body: JSON.stringify({ labels }),
      });
      if (!res.ok) { const body = await res.text(); errors.push({ itemId, step: 'add-labels', message: `GitHub POST /labels ${res.status}: ${body.slice(0,200)}` }); continue; }
      applied.push({ itemId, labels });
    } catch (err) {
      errors.push({ itemId, message: String(err?.message ?? err) });
    }
  }
  console.log(`Applied tags to ${applied.length} issue(s), ${errors.length} error(s)`);
  writeFileSync('/output/result.json', JSON.stringify({ applied, errors, repo, summary: `Applied tags to ${applied.length} issue(s), ${errors.length} error(s)` }));
} catch (err) {
  console.error('apply-tags crashed:', err?.stack || err?.message || String(err));
  process.exit(1);
}
